 1	import React, { FC, useState } from 'react';
 2	
 3	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { ALL_PROJECTS } from '@kubevirt-utils/hooks/constants';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { VM_STATUS } from '@kubevirt-utils/resources/vm/utils/vmStatus';
 7	import { FilterValue } from '@openshift-console/dynamic-plugin-sdk';
 8	import { ERROR } from '@overview/OverviewTab/vm-statuses-card/utils/constants';
 9	import { getVMStatuses } from '@overview/OverviewTab/vm-statuses-card/utils/utils';
10	import VMStatusItem from '@overview/OverviewTab/vm-statuses-card/VMStatusItem';
11	import { Card, CardTitle, ExpandableSection, Grid, Text } from '@patternfly/react-core';
12	import { ProjectDiagramIcon } from '@patternfly/react-icons';
13	
14	import './VirtualMachineListSummary.scss';
15	
16	type VirtualMachineListSummaryProps = {
17	  namespace: string;
18	  onFilterChange?: (type: string, value: FilterValue) => void;
19	  vms: V1VirtualMachine[];
20	};
21	
22	const VirtualMachineListSummary: FC<VirtualMachineListSummaryProps> = ({
23	  namespace,
24	  onFilterChange,
25	  vms,
26	}) => {
27	  const { t } = useKubevirtTranslation();
28	  const [isExpanded, setIsExpanded] = useState<boolean>(true);
29	
30	  const { primaryStatuses } = getVMStatuses(vms || []);
31	
32	  return (
33	    <ExpandableSection
34	      toggleContent={
35	        <Text className="vm-list-summary__expand-section-toggle" component="h3">
36	          <ProjectDiagramIcon className="vm-list-summary__expand-section-toggle-icon" />{' '}
37	          {namespace ?? ALL_PROJECTS}
38	        </Text>
39	      }
40	      className="vm-list-summary__expand-section"
41	      isExpanded={isExpanded}
42	      onToggle={() => setIsExpanded((prev) => !prev)}
43	    >
44	      <Card className="vm-list-summary" data-test-id="vm-list-summary">
45	        <CardTitle component="h5">
46	          {t('Virtual Machines ({{count}})', { count: vms?.length })}
47	        </CardTitle>
48	        <Grid hasGutter>
49	          <VMStatusItem
50	            count={primaryStatuses.Error}
51	            namespace={namespace}
52	            onFilterChange={() => onFilterChange('status', { selected: [ERROR] })}
53	            status={ERROR}
54	          />
55	          <VMStatusItem
56	            count={primaryStatuses.Running}
57	            namespace={namespace}
58	            onFilterChange={() => onFilterChange('status', { selected: [VM_STATUS.Running] })}
59	            status={VM_STATUS.Running}
60	          />
61	          <VMStatusItem
62	            count={primaryStatuses.Stopped}
63	            namespace={namespace}
64	            onFilterChange={() => onFilterChange('status', { selected: [VM_STATUS.Stopped] })}
65	            status={VM_STATUS.Stopped}
66	          />
67	          <VMStatusItem
68	            count={primaryStatuses.Paused}
69	            namespace={namespace}
70	            onFilterChange={() => onFilterChange('status', { selected: [VM_STATUS.Paused] })}
71	            status={VM_STATUS.Paused}
72	          />
73	        </Grid>
74	      </Card>
75	    </ExpandableSection>
76	  );
77	};
78	
79	export default VirtualMachineListSummary;

